class Solution:
    def minimizeConcatenatedLength(self, words):
        def join(x, y):
            if x[-1] == y[0]:
                return x + y[1:]
            return x + y
        n = len(words)
        def rec(i, s):
            if i == n:
                return len(s)
            return min(rec(i + 1, join(s, words[i])), rec(i + 1, join(words[i], s)))
        return rec(1, words[0])

