class Solution:
    def minimizeConcatenatedLength(self, words):
        dp = {}
        first0, last0 = words[0][0], words[0][-1]
        dp[(first0, last0)] = len(words[0])
        for w in words[1:]:
            wf, wl, wlen = w[0], w[-1], len(w)
            ndp = {}
            for (f, l), length in dp.items():
                nf1, nl1 = f, wl
                nlen1 = length + wlen - (1 if l == wf else 0)
                key1 = (nf1, nl1)
                if key1 not in ndp or ndp[key1] > nlen1:
                    ndp[key1] = nlen1
                nf2, nl2 = wf, l
                nlen2 = length + wlen - (1 if wl == f else 0)
                key2 = (nf2, nl2)
                if key2 not in ndp or ndp[key2] > nlen2:
                    ndp[key2] = nlen2
            dp = ndp
        return min(dp.values())

