var minimizeConcatenatedLength = function(words) {
    let dp = new Map();
    const key = (f, l) => f + '|' + l;
    const first0 = words[0][0], last0 = words[0][words[0].length - 1];
    dp.set(key(first0, last0), words[0].length);
    for (let idx = 1; idx < words.length; idx++) {
        const w = words[idx];
        const wf = w[0], wl = w[w.length - 1], wlen = w.length;
        const ndp = new Map();
        for (const [k, length] of dp) {
            const parts = k.split('|');
            const f = parts[0], l = parts[1];
            const nlen1 = length + wlen - (l === wf ? 1 : 0);
            const key1 = key(f, wl);
            if (!ndp.has(key1) || ndp.get(key1) > nlen1) ndp.set(key1, nlen1);
            const nlen2 = length + wlen - (wl === f ? 1 : 0);
            const key2 = key(wf, l);
            if (!ndp.has(key2) || ndp.get(key2) > nlen2) ndp.set(key2, nlen2);
        }
        dp = ndp;
    }
    return Math.min(...dp.values());
};
